  if(command==="/live_verify"){const parts=String(args||"").trim().split(/\s+/).filter(Boolean),id=parts[0]||"",raw=(parts[1]||"").toUpperCase(),status=raw==="PASS"||raw==="OK"?"PASS":raw==="FAIL"||raw==="FAILED"?"FAIL":raw==="WAITING"?"WAITING_DEPLOY":raw==="SOURCE_ONLY"?"SOURCE_ONLY":null,props=await arr(env,"proposals"),p=findProp(props,id);if(!p)return send(c,chatId,"ąØąĄ ąĮą░čłčæą╗ proposal.");if(!status)return send(c,chatId,`ążąŠčĆą╝ą░čé: /live_verify ${p.id} PASS ąĖą╗ąĖ /live_verify ${p.id} FAIL`);const base=p.live_runtime_verify||liveExpectation(p,p.rollback?.done?"rollback":"apply");p.live_runtime_verify={...base,status,confirmed_at:now(),note:parts.slice(2).join(" ")};if(status==="PASS"&&p.state==="verified")p.state="live_verified";if(status==="FAIL")p.state="live_failed";await saveArr(env,"proposals",props,80);return send(c,chatId,["­¤¦¬ Live Verify",`proposal: ${p.id}`,`status: ${status}${status==="PASS"?" Ō£ģ":status==="FAIL"?" ŌØī":" ŌÜĀ’ĖÅ"}`,`command: ${p.live_runtime_verify.command||"ŌĆö"}`,`expected: ${p.live_runtime_verify.expected_reply||"ŌĆö"}`].join("\n"))}
