async function telegram(request,env){const c=await cfg(env),msg=parse(await request.json().catch(()=>null));if(!msg)return out({ok:true});if(!ownerOk(c,msg.userId)){await send(c,msg.chatId,"Ōøö ąöąŠčüčéčāą┐ ąĘą░ą║čĆčŗčé.");return out({ok:true,denied:true})}try{if(msg.command&&!CMDS.has(msg.command)){await send(c,msg.chatId,`ąØąĄ ąĘąĮą░čÄ ą║ąŠą╝ą░ąĮą┤čā ${msg.command}. /help ŌĆö čüą┐ąĖčüąŠą║. ą£ąŠą┤ąĄą╗čī ąĮąĄ ą▓čŗąĘčŗą▓ą░čÄ.`);return out({ok:true,unknown_command:true,version:VERSION})}await handle(env,c,msg);return out({ok:true,command:msg.command||"text",version:VERSION})}catch(e){await send(c,msg.chatId,`ŌØī Core error: ${clip(e.message||e,1000)}`);return out({ok:false,error:String(e.message||e),version:VERSION},500)}}
